INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000038', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000038', 'S''assurer que le gros fer rentre dans le profilé antichute.', 'Diamètre profilé', 'Suva 33055', 'Les protections sont en général testées pour des fers de diamètres de 10 à 22 mm.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000039', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000039', 'Demander le bon de contrôle du chef coffreur.', 'Validation', 'Suva 33033', 'Le coffrage de dalles doit être inspecté par un spécialiste avant de couler.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000040', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000040', 'Vérifier l''élimination des dangers post-décoffrage', 'Art. 16', 'RPAC', 'Les aspérités dangereuses (clous, vis) doivent être éliminées aussitôt le décoffrage effectué', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000041', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000041', 'Vérifier les fers de fondation qui dépassent.', 'Piquets métal', 'Suva 33055', 'Ils doivent être obligatoirement repliés en forme de crochet pour éviter l''empalement.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000042', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000042', 'S''assurer que la dalle ne glisse pas sur le côté.', 'Poussée au vide', 'Suva 33033', 'Le système de coffrage doit absorber au moins 3% du poids de la dalle en horizontal.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000043', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000043', 'Vérifier l''instruction avant de lever le panneau bois.', 'Décoffrage', 'Suva 33011', 'Le supérieur doit ordonner de bien sécuriser le panneau avant d''ôter les attaches', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000044', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000044', 'Vérifier la poutrelle jaune (Doka) sous la dalle.', 'Sens de poutrelle', 'Suva 33014', 'Les poutrelles de coffrage H20 ne doivent jamais être positionnées à plat', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000045', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000045', 'Contrôler les faux-planchers en bois croisé dans les murs.', 'Bricolages bois', 'Suva 33018', 'Les planchers bricolés en bois sont dangereux, privilégier des tours d''étayage modernes', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000046', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000046', 'Périmètre de sécurité balisé', 'RPAC 16', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000047', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000047', 'Vérifier les bouchons oranges/profilés mis sur les fers.', 'Champignons plastique', 'Suva 33055', 'Les bouchons doivent être testés par le fabricant contre la perforation sous un homme de 100kg', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000048', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000048', 'Pousser légèrement le panneau de coffrage pour tester.', 'Stabilité murs', 'Suva 33011', 'Les coffrages muraux doivent être assurés en permanence contre le renversement', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000049', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000049', 'Observer comment la liasse de fer est transportée.', 'Levage botte de fer', 'Suva 33055', 'Les bottes de fer ne doivent pas glisser hors de l''élingue pendant le grutage', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000050', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000050', 'Vérifier le sommet des étais jaunes de dalle.', 'Jonctions dalles', 'Suva 33014', 'Des têtes à fourche en U sont obligatoires à la jonction des poutrelles en bois', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000051', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000051', 'Vérifier comment l''ouvrier vibre le béton en haut.', 'Travail en hauteur', 'Suva 33011', 'Des échelles avec plateforme sont obligatoires dès 50 cm de hauteur de chute.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000052', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000002', 'bb000000-0000-4000-a000-000000000052', 'Vérifier les bras diagonaux du coffrage.', 'Fixation sol', 'Suva 33011', 'Ancrés de façon à résister à de fortes forces de traction et de compression.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000053', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000053', 'Contrôler la transmission de l''information en cas de sinistre', 'Art. 35', 'RPAC', 'Avis immédiat à la commune si dommage à un tiers, et annonce à la SUVA pour tout accident de chantier', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000054', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000054', 'Vérifier l''envoi de l''avis d''ouverture et de montage à la commune.', 'Art. 5', 'RPAC', '10 jours à l''avance au moins pour l''ouverture, les grues et échafaudages', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000055', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000055', 'Lampes rouges et catadioptres', 'RPAC 24', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000056', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000056', 'Accessibles et fonctionnels', 'OTConst 75', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000057', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000057', 'Contrôler le port du casque de protection (et de la jugulaire selon travaux).', 'Art. 6', 'OTConst', 'Jugulaire requise pour travaux sur cordes, antichute et hélicoptère', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000058', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000058', 'Vérifier la résistance de la clôture et la présence de panneaux d''interdiction au public', 'Art. 7', 'RPAC', 'Aménagements piétons obligatoires tenant compte des handicapés physiques et de la vue', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000059', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000059', 'Auto-sauveteurs disponibles sur site', 'OTConst 108', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000060', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000060', 'Vérifier que chaque entrepreneur a contrôlé ses installations', 'Art. 34', 'RPAC', 'L''entrepreneur est responsable de s''assurer de la conformité avant tout travail, même s''il n''est pas propriétaire du matériel', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000061', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000061', 'Vérifier l''absence de conduites ou lignes sous tension.', 'Art. 30', 'OTConst', 'L''existence d''installations dangereuses doit être contrôlée avant les travaux', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000062', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000003', 'bb000000-0000-4000-a000-000000000062', 'Contrôler le respect des normes environnementales et de protection des eaux', 'Art. 14', 'RPAC', 'Incinération de déchets de chantiers strictement interdite', true, false);
