INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000206', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000011', 'bb000000-0000-4000-a000-000000000201', 'Identification précise', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000207', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000011', 'bb000000-0000-4000-a000-000000000202', 'Règles classes 1M, 2, 2M connues (ne pas diriger sur autrui)?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000208', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000011', 'bb000000-0000-4000-a000-000000000203', 'Longueur d''onde, puissance, énergie', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000209', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000011', 'bb000000-0000-4000-a000-000000000204', 'Supérieurs contrôlent le respect des règles?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000210', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000011', 'bb000000-0000-4000-a000-000000000205', 'Signalétique visuelle', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000211', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000206', 'Vérifier si le foret ou le disque chauffe excessivement.', 'Lames & Disques', 'Suva 67092', 'Ils doivent être affûtés et strictement adaptés au type de matériau usiné.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000212', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000207', 'Pousser un bois sous la scie.', 'Scie circulaire table', 'Suva 67003', 'La cape protectrice (Suva B90) doit s''abaisser d''elle-même sur la pièce de bois.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000213', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000208', 'Vérifier que le capot de la meuleuse d''angle n''est pas ôté.', 'Protection disque', 'Suva 67092', 'Les machines doivent conserver tous les dispositifs de protection fournis à l''origine.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000214', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000209', 'Vérifier la fiche et la plaque signalétique de la meuleuse.', 'Double isolation', 'Suva 67092', 'Exiger la double isolation (symbole double carré) ou une prise de terre à 3 broches.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000215', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000210', 'Regarder la fine lame en métal derrière les dents de scie.', 'Scie circulaire table', 'Suva 67003', 'Obligatoire et doit être réglé près des dents pour éviter le rejet violent du bois.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000216', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000211', 'Carters de protection en place', 'OTConst 74', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000217', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000212', 'Vérifier le marquage "RPM" sur le disque abrasif.', 'Concordance vitesse', 'Suva 67092', 'Le diamètre et la vitesse de rotation max du disque doivent correspondre à la meuleuse.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000218', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000213', 'Vérifier l''étiquette de marquage et le manuel de l''outil.', 'CE', 'Suva 67092', 'Pour les achats post-1997, une déclaration CE du fabricant doit être disponible.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000219', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000214', 'Regarder le dos de la perceuse/scie.', 'Surchauffe moteur', 'Suva 67092', 'La grille de ventilation du moteur ne doit pas être bouchée par la poussière de chantier.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000220', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000215', 'Débrancher/rebrancher la scie en marche à vide pour tester.', 'Scie circulaire table', 'Suva 67003', 'La machine ne doit pas redémarrer toute seule après une coupure de courant', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000221', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000216', 'Vérifier la scie le soir.', 'Scie circulaire table', 'Suva 67003', 'Laissée dehors, elle doit être recouverte d''une bâche étanche après le travail', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000222', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000217', 'Demander qui répare les câbles des perceuses cassées.', 'Entretien', 'Suva 67092', 'L''entretien électrique doit être confié à une personne qualifiée (selon norme SNG 482638)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000223', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000218', 'Chercher les outils pour pousser les petites pièces.', 'Scie circulaire table', 'Suva 67003', 'Un poussoir longitudinal et un latéral doivent être stockés sur la scie', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000224', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000219', 'Couteau diviseur présent', 'OTConst 76', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000225', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000012', 'bb000000-0000-4000-a000-000000000220', 'Contrôler le bout de la raboteuse/ponceuse à bois.', 'Poussières nocives', 'Suva 67092', 'Elles doivent être équipées d''un sac de collecte des copeaux ou raccordées à un aspi', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000226', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000221', 'Vérifier l''odeur dans le local fermé.', 'Cloueuses à gaz', 'Suva 67141', 'Interdit en local confiné, l''usage de cartouches à gaz nécessite aération et précautions feu.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000227', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000222', 'Contrôler l''ergonomie et la sécurité des cloueuses au gaz/air.', 'Fiche 67141', 'Suva 67141', 'Le palpeur de sécurité doit être présent. Les cloueuses de > 2,5 kg nécessitent un anneau de suspension (équilibreur), et celles > 6 kg une poignée supplémentaire.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000228', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000223', 'Vérifier qu''aucun dispositif de sécurité n''est mis hors service.', 'Fiche 67146', 'Suva 67146', 'Il est interdit de shunter un contacteur ou de retirer un capot pour aller plus vite. Les réglages doivent pouvoir se faire en sécurité ou à l''arrêt', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000229', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000224', 'Appuyer la gâchette dans le vide.', 'Tir de clous', 'Suva 67141', 'Le tir ne part que par appui simultané de la gâchette et pression de l''outil contre le mur', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000230', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000225', 'Vérifier la connexion du tuyau d''air au pistolet.', 'Tuyau pneumatique', 'Suva 67141', 'Tuyaux d''air comprimé équipés de raccords de sécurité (qui ne sifflent pas au débranchement)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000231', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000226', 'Vérifier les dispositifs de protection de la lame.', 'Fiche 67003', 'Suva 67003', 'La cape de protection doit s''abaisser sur la pièce, le couteau diviseur doit être réglé (écart max avec la lame de 8-10 mm) et des poussoirs doivent être disponibles', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000232', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000013', 'bb000000-0000-4000-a000-000000000227', 'Vérifier le tir de clous > 100mm.', 'Gros clous', 'Suva 67141', 'Si >100mm, déclenchement unique imposé : relâcher gâchette entre chaque clou', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000233', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000228', 'Contre envol par vent fort', 'RPAC 10', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000234', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000229', 'Aspi HEPA pour quartz/béton', 'OTConst 13', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000235', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000230', 'Boutefeu diplômé uniquement', 'OTConst 85', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000236', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000231', 'Contrôler le port des protections auditives.', 'Art. 36', 'OTConst', 'Port obligatoire si la valeur limite d''exposition est dépassée', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000237', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000232', 'S''assurer de la protection contre les conditions climatiques extrêmes.', 'Art. 37', 'OTConst', 'Mesures contre le soleil, la forte chaleur et le froid', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000238', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000233', 'Respect des seuils VME', 'OTConst 106', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000239', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000234', 'Vérifier les mesures (avalanches, chutes de pierres).', 'Art. 39', 'OTConst', 'Surveillance, alerte secours et transport garantis. Zone évacuée si danger', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000240', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000235', 'Protection dès 85 dB(A)', 'OTConst 11', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000241', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000236', 'Filtres ou aspi obligatoires', 'OTConst 12', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000242', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000237', 'Vérifier la présence d''extincteurs et les voies d''évacuation.', 'Art. 34', 'OTConst', 'Barricade et panneau triangulaire requis pour les zones à risque d''explosion', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000243', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000238', 'éclairage de secours obligatoire', 'OTConst 107', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000244', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000239', 'Visibilité parfaite des postes', 'OTConst 73', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000245', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000240', 'Vérifier l''information aux travailleurs si présence d''amiante suspectée.', 'Art. 32', 'OTConst', 'Interruption immédiate et information du maître d''ouvrage si trouvée', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000246', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000241', 'Pare-éclats obligatoires', 'OTConst 86', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000247', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000242', 'Mesures chaleur (>30°) / Froid', 'OTConst 10', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000248', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000243', 'Contrôler l''air ambiant dans les espaces confinés/souterrains.', 'Art. 33', 'OTConst', 'Entre 19% et 21% d''O2. Contrôle régulier. Appareils respi si besoin', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000249', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000244', 'Contrôler la présence d''EPI et de sauvetage près de l''eau.', 'Art. 35', 'OTConst', 'Gilets de sauvetage, bouées, bateaux (pour eaux courantes)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000250', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000014', 'bb000000-0000-4000-a000-000000000245', 'Vérifier le niveau d''éclairage des accès et postes de travail.', 'Art. 38', 'OTConst', 'Doit être "suffisant"', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000251', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000246', 'Vérifier que les postes de travail offrent la sécurité voulue avec des protections contre les chutes.', 'Art. 9', 'OTConst', 'Pose de protections contre les chutes (Art. 22 à 29)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000252', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000247', 'Contrôler les platelages utilisés dans les cages d''ascenseur.', 'Fiche 44046', 'Suva 44046', 'Il est strictement interdit d''utiliser des panneaux de coffrage multicouches comme platelages. L''épaisseur minimale du bois doit être de 45 mm avec un bois de classe C 24.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000253', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000248', 'Contrôler l''état des sols et l''absence d''obstacles.', 'Fiche 67012', 'Suva 67012', 'Les différences de niveau supérieures à 4 mm sont considérées comme un risque de trébuchement. Les câbles et tuyaux doivent être sortis des zones de passage.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000254', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000249', 'Vérifier le moyen d''accès en cas de dénivelé.', 'Art. 15', 'OTConst', 'Escaliers ou équipements sûrs obligatoires si dénivelé > 50 cm', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000255', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000250', 'Vérifier l''absence de personnes dans la zone de danger des machines.', 'Art. 19', 'OTConst', 'Utilisation de caméras, miroirs ou d''un signaleur. Marche arrière limitée', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000256', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000251', 'Contrôler le mode d''évacuation des gravats et matériels depuis la hauteur.', 'Art. 18', 'OTConst', 'Zone barricadée ou utilisation de glissières/canaux fermés', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000257', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000252', 'Mesurer la largeur des voies de circulation et contrôler les accès.', 'Art. 11', 'OTConst', 'Voies d''accès : min. 1 m. Autres : min. 60 cm. Escaliers si > 5 marches', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000258', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000253', 'Contrôler que les fers d''armature et objets pointus sont protégés.', 'Art. 10', 'OTConst', 'Fers saillants recourbés ou recouverts de protections', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000259', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000254', 'S''assurer de la solidité des passerelles.', 'Art. 13', 'OTConst', 'Doivent être assurées contre le glissement', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000260', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000255', 'Mesurer l''espace libre entre les installations en mouvement et les obstacles.', 'Art. 14', 'OTConst', 'Espace libre exigé : 0,5 m de large et 2,5 m de haut. Sinon, barricader', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000261', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000256', 'Contrôler la présence de barrières ou de panneaux interdisant l''accès aux surfaces non résistantes.', 'Art. 12', 'OTConst', 'Passage obligatoire sur passerelles avec garde-corps des deux côtés', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000262', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000257', 'Contrôler la solidité des ponts, bermes et digues.', 'Art. 16', 'OTConst', 'Justificatif d''ingénieur requis. Distance bordure : min. 1 m', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000263', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000015', 'bb000000-0000-4000-a000-000000000258', 'Vérifier les protections contre la chute ou l''écroulement d''éléments.', 'Art. 17', 'OTConst', 'Pas de danger pour les postes et passages en dessous', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000264', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000259', 'La rétention des liquides écoulés se fait via des bacs ou seuils hauts.', 'Rétention', 'Suva 67071', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000265', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000260', 'Un mauvais stockage présente un très grand risque d''incendie et d''explosio.', 'Stockage', 'Suva 44013', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000266', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000261', 'Des dispositifs d''extinction appropriés doivent être installés.', 'Extinction', 'Suva 67071', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000267', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000262', 'Contrôler la surveillance des travaux à chaud et la recherche d''amiante', 'Art. 11', 'RPAC', 'Extincteur requis pour soudage/meulage. Contrôle post-travail si risque de feu couvant. Amiante à suspecter lors de rénovations', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000268', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000263', 'Vérifier l''instruction des ouvriers sur les produits chimiques.', 'Règles base', 'Suva 44013', 'Des instructions compréhensibles doivent être rédigées et consignées', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000269', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000264', 'Protection des récipients contre d''importants effets thermiques', 'Ignition', 'Suva 67071', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000270', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000265', 'Il faut porter des gants appropriés pour se protéger des durcisseurs', 'EPI peau', 'Suva 44013', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000271', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000266', 'Vérifier le stockage des liquides avec point d''éclair < 30°C.', 'Fiche 67071', 'Suva 67071', 'Le local doit être aéré (renouvellement de l''air 3 à 5 fois par heure). En zone 2 (0 à 1 m du sol), il ne doit y avoir aucune source d''ignition, ni étincelle', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000272', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000267', 'Ronde 1h après fin travail', 'RPAC 11', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000273', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000268', 'Les locaux de stockage ont besoin d''une ventilation naturelle ou artificielle', 'Aération', 'Suva 67071', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000274', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000269', 'Ne pas entreposer de matériaux solides combustibles près des liquides inflammables', 'Roulottes', 'Suva 33030', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000275', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000270', 'Pour les petites quantités, utiliser des armoires en matériau ininflammable', 'Stockage local', 'Suva 67071', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000276', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000271', 'Une personne compétente pour la protection de la santé doit être désignée', 'Délégation', 'Suva 44013', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000277', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000016', 'bb000000-0000-4000-a000-000000000272', 'Privilégier les liquides inflammables ayant un point d''éclair supérieur à 30 °C', 'Point d''éclair', 'Suva 67071', '', true, false);
