INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000283', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000278', 'Vérifier l''installation des filets plateforme (avec sangles).', 'Fiche 33026', 'Suva 33026', 'L''inclinaison maximale du filet est de 20°, au-delà les travailleurs doivent s''encorder [8]. Un espace libre d''au moins 3 m doit être garanti sous le filet.', true, false);
