INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000285', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000280', 'Vérifier que la planche ne peut pas glisser.', 'Dalles', 'Suva 67008', 'Une couverture simplement posée peut glisser et entraîner la mort.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000286', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000281', 'Vérifier la résistance des barrières bois.', 'Dalles', 'Suva 67008', 'Chaque partie du garde-corps doit supporter une charge de 100 kg (1000 N).', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000287', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000282', 'Mesurer les dimensions des garde-corps périphériques (Lisse, plinthe).', 'Art. 22', 'OTConst', 'Lisse haute à min. 100 cm, plinthe 15 cm. Écart max : 47 cm', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000288', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000283', 'Contrôler la présence de garde-corps selon la hauteur et l''environnement.', 'Art. 23', 'OTConst', 'Obligatoire si chute > 2 m, talus > 2 m (pente > 45°), ou près de l''eau', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000289', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000284', 'Contrôler les protections de trémies.', 'Dalles', 'Suva 67008', 'Elles sont protégées par des garde-corps d''au moins 1 m de haut.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000290', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000285', 'Dépassement 60cm du plan toit', 'OTConst 65', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000291', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000286', 'Vérifier la composition du garde-corps.', 'Garde-corps', 'Suva 33017', 'Il doit comporter une lisse haute, intermédiaire, et une plinthe', true, false);
