INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000293', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000288', 'Contrôler les justificatifs si un garde-corps ou échafaudage est impossible.', 'Art. 29', 'OTConst', 'Mesures doivent être fixées par écrit par un spécialiste de la sécurité', true, false);
