INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000295', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000290', 'Vérifier la sécurité quand la trappe est soulevée.', 'Dalles', 'Suva 67008', 'Protéger l''ouverture avec des garde-corps escamotables ou barrières', true, false);
