INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000305', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000300', 'Vérifier le montage des échafaudages lors de la construction de bâtiments.', 'Art. 26', 'OTConst', 'Requis dès 3 m de chute. Garde-corps doit dépasser la zone de 80 cm', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000306', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000017', 'bb000000-0000-4000-a000-000000000301', 'Vérifier la fixation avant l''accès.', 'Art. 28', 'OTConst', 'Accès autorisé uniquement si les éléments sont fixés', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000307', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000018', 'bb000000-0000-4000-a000-000000000302', 'Contrôler l''obligation d''annonce pour les carrières et terrassements.', 'Art. 102', 'OTConst', 'Obligatoire si abattage rocheux > 5000 m³ (14 jours avant)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000308', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000018', 'bb000000-0000-4000-a000-000000000303', 'Vérifier la hauteur du front de taille.', 'Art. 106', 'OTConst', 'Extraction depuis le bas limitée à la hauteur d''atteinte de la machine', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000309', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000018', 'bb000000-0000-4000-a000-000000000304', 'Vérifier la pente de la découverte (front de taille).', 'Art. 103-104', 'OTConst', 'Pente max 45°. Distance min de 1 m entre le pied et l''angle', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000310', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000018', 'bb000000-0000-4000-a000-000000000305', 'Contrôler la purge de la paroi.', 'Art. 110', 'OTConst', 'Après intempéries, purge obligatoire des surplombs et matériaux instables', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000311', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000018', 'bb000000-0000-4000-a000-000000000306', 'Contrôler la sécurisation du personnel sur terrain escarpé.', 'Art. 107-108', 'OTConst', 'Sape interdite. Assurage encordé obligatoire (art. 22-29)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000312', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000018', 'bb000000-0000-4000-a000-000000000307', 'Vérifier la protection des cabines de machines.', 'Art. 109', 'OTConst', 'Cabines de conduite équipées de grilles anti-chutes de pierres', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000313', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000019', 'bb000000-0000-4000-a000-000000000308', 'Contrôler le niveau de bruit et le port des protecteurs d''ouïe.', 'Fiche 67009', 'Suva 67009', 'Le port est obligatoire dès 85 dB(A) et la zone doit être signalée par un panneau bleu. Des examens audiométriques préventifs doivent être proposés aux moins de 40 ans.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000314', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000019', 'bb000000-0000-4000-a000-000000000309', 'Vérifier la formation et le plan de sauvetage.', 'Fiche 44002', 'Suva 44002', 'Les travailleurs utilisant un harnais doivent être formés (min. 1 jour). Un plan de sauvetage doit garantir qu''une personne suspendue sera secourue en 20 minutes maximum.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000315', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000019', 'bb000000-0000-4000-a000-000000000310', 'Contrôler les mesures de protection contre les produits chimiques.', 'Fiche 44074', 'Suva 44074', 'Le contact cutané avec des résines (époxy, PU), ciments ou solvants peut causer des eczémas graves. L''utilisation de gants adaptés et de crèmes de soin est requise', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000316', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000019', 'bb000000-0000-4000-a000-000000000311', 'Vérifier la classe des vêtements sur la voie publique.', 'Fiche 33076', 'Suva 33076', 'Les collaborateurs doivent porter des vêtements de signalisation certifiés de Classe 3 (couvrant torse et jambes) si la vitesse routière dépasse 60 km/h ou par visibilité réduite (nuit, brouillard)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000317', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000312', 'Contrôler la date d''annonce des travaux souterrains.', 'Art. 87', 'OTConst', 'Obligatoire auprès de la SUVA 14 jours avant exécution', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000318', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000313', 'Contrôler la séparation entre piétons et voies ferrées souterraines.', 'Art. 98', 'OTConst', 'Séparation par des mesures techniques obligatoires', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000319', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000314', 'S''assurer de la protection des ouvriers (chaleur/humidité).', 'Art. 90', 'OTConst', 'Mesures appropriées selon le climat souterrain', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000320', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000315', 'Vérifier la visibilité des conducteurs d''engins souterrains.', 'Art. 96', 'OTConst', 'Visibilité permanente de la zone de danger dans le sens de marche', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000321', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000316', 'Si < 600 mm : usage de robots', 'OTConst 119', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000322', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000317', 'Vérifier la détection des gaz (grisou/radon).', 'Art. 92', 'OTConst', 'Mesures si couches rocheuses contiennent du gaz naturel', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000323', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000318', 'Vérifier le respect de la temporisation post-tir.', 'Art. 100', 'OTConst', 'Reprise des travaux autorisée au plus tôt 15 minutes après l''explosion. Purge obligatoire', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000324', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000319', 'Contrôler le type de motorisation des engins dans le tunnel.', 'Art. 93', 'OTConst', 'Moteurs essence/gaz liquide strictement interdits dans les souterrains', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000325', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000320', 'Vérifier la protection des gaines d''aération.', 'Art. 97', 'OTConst', 'Tuyaux d''amenée d''air frais protégés contre les dommages physiques', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000326', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000321', 'Vérifier les sondages préalables à l''excavation.', 'Art. 99', 'OTConst', 'Sondage d''éboulement ou de venue d''eau avant excavation', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000327', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000322', 'Contrôler les mesures lors de rénovation de tunnel sous trafic.', 'Art. 95', 'OTConst', 'Séparation physique protégeant les travailleurs du flux', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000328', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000323', 'Mesurer l''espace utile et vérifier la surveillance.', 'Art. 119', 'OTConst', 'Surveillant externe permanent. Si < 600 mm : travaux exclusifs par robots', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000329', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000324', 'Vérifier le concept de ventilation et de qualité de l''air.', 'Art. 91', 'OTConst', 'Espaces ventilés obligatoires, ou mesure permanente de l''air exigée', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000330', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000325', 'Arrivée d''air frais continue', 'OTConst 105', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000331', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000326', 'Vérifier le port d''EPI haute visibilité dans le tunnel.', 'Art. 101', 'OTConst', 'Doit couvrir "toutes les parties du corps"', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000332', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000327', 'Vérifier l''éclairage de secours.', 'Art. 94', 'OTConst', 'Éclairage de secours central ou lampe individuelle par travailleur requis', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000333', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000020', 'bb000000-0000-4000-a000-000000000328', 'Vérifier les alimentations de secours.', 'Art. 88-89', 'OTConst', 'Requis pour l''aération, les pompes, l''éclairage, l''avertisseur gaz', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000334', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000329', 'Echelles fixées mécaniquement', 'RPAC 22', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000335', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000330', 'Vérifier la présence de dispositifs d''ancrage pour l''entretien futur des façades', 'Art. 24', 'RPAC', 'Obligatoire pour les façades rideaux inaccessibles aux camions-nacelles', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000336', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000331', 'Vérifier comment les échelles de toit sont fixées.', 'Échelles couvreur', 'Suva 67018', 'Les crochets d''ancrage doivent répondre aux normes SN EN 517.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000337', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000332', 'Contrôler la pose de barres de sécurité et de crochets à demeure', 'Art. 23', 'RPAC', 'Barres à 2 traverses, distante de min 14 cm du toit, crochets espacés de max 1.65 m 17. Crochet fermé requis pour chaque accès', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000338', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000333', 'Contrôler les extrémités du toit (pignons).', 'Pignons', 'Suva 44077', 'Des protections contre les chutes sont exigées également sur les pignons.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000339', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000334', 'Vérifier comment le filet de bord de toit est fixé.', 'Paroi couvreur', 'Suva 33022', 'Interdiction de fixer avec des colliers de serrage en plastique (sauf certifié).', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000340', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000335', 'Vérifier le certificat EPI antichute.', 'Formation EPI', 'Suva 67018', 'La formation au port du harnais et au sauvetage dure au minimum une journée.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000341', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000336', 'Vérifier les rubalises sur les toits plats.', 'Toit plat', 'Suva 67018', 'La zone doit être délimitée par des barrières solides, la rubalise ne suffit pas.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000342', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000337', 'Contrôler le bout de l''échelle contre la gouttière.', 'Accès échelle', 'Suva 67018', 'L''échelle simple doit dépasser d''au moins 1 m le bord du toit et être attachée.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000343', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000338', 'Ancrées aux chevrons', 'OTConst 67', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000344', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000339', 'Contrôler le harnais pour réparations < 2 jours.', 'Petits travaux', 'Suva 67018', 'Pour des travaux très courts, l''EPI antichute est obligatoire si la chute > 3 m.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000345', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000340', 'Min. 60 cm de passage libre', 'OTConst 66', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000346', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000341', 'Vérifier l''échafaudage pour changer une gouttière.', 'Rénovation chéneau', 'Suva 44077', 'Plateaux de 60 cm sur consoles avec une plinthe de 15 cm sont suffisants', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000347', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000342', 'Vérifier si le garde-corps du toit est rehaussé.', 'Paroi couvreur', 'Suva 33022', 'Des ancrages complémentaires sont nécessaires si la paroi dépasse 2,0 m de haut', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000348', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000343', 'Contrôler le trottoir sous l''avant-toit.', 'Danger public', 'Suva 67018', 'Le périmètre dangereux au sol doit être physiquement délimité et signalé', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000349', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000344', 'Vérifier comment les ouvriers marchent sur des tôles.', 'Cheminement', 'Suva 67018', 'Sur des toitures fragiles, on travaille exclusivement depuis des passerelles réparties', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000350', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000345', 'Contrôler la circulation sur toit amiante/fibrociment.', 'Fibrociment', 'Suva 33027', 'Les plaques en fibrociment sont toujours considérées comme non résistantes à la rupture', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000351', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000346', 'Conformité plans et normes SIA', 'RPAC 23', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000352', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000347', 'Vérifier la sécurisation des coupoles et éléments translucides.', 'Fiche 44066', 'Suva 44066', 'Les coupoles en matière synthétique sont considérées comme non résistantes à la rupture et exigent une protection collective (grillage, filet', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000353', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000348', 'S''assurer qu''un ouvrier suspendu peut être sauvé.', 'Sauvetage', 'Suva 67018', 'La sécurisation et le sauvetage d''une personne suspendue doivent s''opérer en max 20 min [93].', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000354', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000349', 'S''assurer de la solidité du plancher extérieur.', 'Pont de ferblantier', 'Suva 33021', 'Le platelage résiste à une chute dynamique d''une boule de 100 kg (EN 12810-2)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000355', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000350', 'Vérifier l''équipement pour toits très pentus.', 'Pente forte', 'Suva 44066', 'Des échelles de couvreur sont nécessaires en plus du harnais', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000356', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000351', 'Vérifier le harnais sur toit humide/neige.', 'Petits travaux', 'Suva 67018', 'L''EPI antichute est requis dès 2 m de chute en cas de risque de glissade', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000357', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000352', 'Vérifier les mesures pour travaux très courts (< 2 jours-personne).', 'Art. 46', 'OTConst', 'Chute > 3 m = EPI antichute obligatoires', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000358', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000021', 'bb000000-0000-4000-a000-000000000353', 'Évaluer la pente du toit et la hauteur de chute pour exiger l''échafaudage', 'Art. 22', 'RPAC', 'Exigé si bas du toit ≥ 3m ET pente > 20% (métal/plastique) ou > 40% (tuile/ardoise)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000359', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000354', 'Pas de fente > 3cm entre madriers', 'OTConst 28', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000360', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000355', 'Vérifier les points de fixation à la façade.', 'Art. 51', 'OTConst', 'Posés au fur et à mesure du montage pour résister à la traction/compression', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000361', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000356', 'Socles stables, pas de briques', 'OTConst 57', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000362', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000357', 'Mesurer les dimensions des plateaux de garde (auvents) au-dessus de la rue', 'Art. 19', 'RPAC', 'Inclinés à 45°, hauteur min 1.50 m, bord inférieur à min 4.50 m au-dessus de la chaussée. Sans vide avec la façade', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000363', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000358', 'Mesurer la largeur du platelage et vérifier la classe de charge.', 'Art. 55', 'OTConst', 'Léger (peinture) = 60 cm (2.0 kN/m²). Lourd (maçonnerie) = 90 cm (3.0 kN/m²)', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000364', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000359', 'Mesurer l''espace entre plateau et façade.', 'Art. 57', 'OTConst', 'La distance ne peut dépasser 30 cm, sinon un garde-corps intérieur est exigé [55].', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000365', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000360', 'Tester la flexion en marchant dessus.', 'Platelages', 'Suva 33020', 'La déformation maximale est de 25 mm en essai de charge sous un ouvrier.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000366', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000361', 'Vérifier la neige sur les ponts d''échafaudage.', 'Art. 61', 'OTConst', 'La neige, la glace et les gravats doivent être enlevés des platelages.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000367', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000022', 'bb000000-0000-4000-a000-000000000362', 'Vérifier la hauteur de pose des filets de protection.', 'Art. 67', 'OTConst', 'Posés pour éviter une chute > 3 m', true, false);
