INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000401', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000023', 'bb000000-0000-4000-a000-000000000396', 'Vérifier par où l''ouvrier grimpe.', 'Accès', 'Suva 67150', 'Il faut utiliser uniquement les moyens d''accès prévus à l''intérieur du cadre', true, false);
