INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000413', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000408', 'Personnel instruit à l''utilisation correcte?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000414', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000409', 'Garde-corps ou EPI si chute > 2m', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000415', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000410', 'Supérieurs contrôlent le comportement?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000416', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000411', 'Sécurité renforcée près de zones à risque (balcon)?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000417', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000412', 'Vérifier que l''utilisation de l''échelle portable est justifiée.', 'Art. 21', 'OTConst', 'Si chute > 2 m, travaux de courte durée et protection antichute exigés', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000418', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000413', 'Barrières ou signalisation', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000419', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000024', 'bb000000-0000-4000-a000-000000000414', 'Contrôler la pertinence et la sécurité des échelles simples.', 'Fiche 44026', 'Suva 44026', 'Une échelle simple ne sert que de moyen d''accès et doit dépasser d''au moins 1 m le bord. À privilégier : échelles mobiles avec plateforme (PEMP) ou escabeaux limités à 1 m de chute.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000420', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000415', 'Demander le papier de conformité du gros coffret central.', 'Légalité installation', 'Suva 67081', 'L''installation électrique doit être réalisée et certifiée par un installateur agréé.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000421', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000416', 'Vérifier que les boîtiers électriques ne sont pas cassés.', 'Contacts apparents', 'Suva 67081', 'Toutes les parties conductrices de tension (prises, interrupteurs) doivent être fermées.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000422', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000417', 'Lire les écritures imprimées sur la gaine de rallonge.', 'Type de câbles', 'Suva 67081', 'Utiliser des câbles renforcés lourds type H07RN-F ou H07BQ-F adaptés à l''eau et aux chocs.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000423', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000418', 'Vérifier tout le long de la rallonge orange au sol.', 'Câbles 220V', 'Suva 67081', 'Aucun câble sectionné, dénudé ou réparé avec du ruban adhésif (scotch) n''est toléré.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000424', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000419', 'Pas d''arrachement', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000425', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000420', 'Contrôler les fils qui pendent du plafond/mur brut.', 'Attentes mur', 'Suva 67081', 'Doivent être isolés avec des gaines thermo-rétractables ou des bornes plastiques sécurisées.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000426', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000421', 'Min 5.0m (selon tension)', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000427', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000422', 'Regarder le coffret électrique rouge/noir de chantier.', 'Sécurité différentielle', 'Suva 67081', 'Un Dispositif Différentiel Résiduel (DDR de 30mA) est obligatoire pour protéger la vie humaine.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000428', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000423', 'Vérifier la couleur des prises de grosse puissance.', 'Fiches triphasé', 'Suva 67081', 'Les fiches de courant alternatif à cinq pôles pour le chantier doivent être rouges et rondes.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000429', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000424', 'Hauteur min. 4.5m', 'RPAC 08', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000430', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000425', 'Pas de fiches modifiées/sciées', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000431', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000426', 'Responsable maintenance désigné et connu?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000432', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000427', 'S''assurer qu''aucun fil caché ne traverse la zone de percement.', 'Forage murs', 'Suva 67081', 'Consulter les plans et utiliser des détecteurs avant de fraiser les murs [144].', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000433', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000428', 'Réparations confiées à des spécialistes qualifiés?', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000434', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000429', 'Vérifier mèche/foret', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000435', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000430', 'Adapté aux chantiers', '', 'Liste de contrôle', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000436', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000431', 'Vérifier la rallonge noire enroulée autour de son axe.', 'Bobines', 'Suva 67081', 'Pour de grandes puissances, le câble doit être déroulé complètement pour éviter le feu', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000437', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000025', 'bb000000-0000-4000-a000-000000000432', 'Vérifier la conformité des branchements et rallonges.', 'Fiche 67081', 'Suva 67081', 'Les machines triphasées doivent avoir des prises CEE à 5 pôles (rouges). Un Dispositif Différentiel Résiduel (DDR) est obligatoire et les câbles ne doivent pas être rafistolés au scotch', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000438', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000433', 'Observer l''angle du câble pendant qu''on relève le mur.', 'Levage grue', 'Suva 67095', 'Le câble doit rester à la verticale pour éviter le ripage et coincement de l''ouvrier.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000439', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000434', 'Vérifier l''ordre des opérations du transporteur.', 'Chargement', 'Suva 67095', 'Chaque mur est stabilisé sur le camion avant d''enlever les sangles de transport.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000440', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000435', 'S''assurer de la stabilité avant libération de la charge.', 'Libération grue', 'Suva 84048', 'L''élément en acier ne doit pas être détaché de la grue avant d''être boulonné solidement.', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000441', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000436', 'étayage immédiat selon plan', 'OTConst 31', 'OTConst', '', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000442', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000437', 'Contrôler comment le panneau tient debout.', 'Serre-joints', 'Suva 67095', 'Les lattes pointées et serre-joints sont inadaptés et interdits pour stabiliser un mur lourd', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000443', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000438', 'Vérifier l''inclinaison des sangles qui lèvent le bois.', 'Traverses', 'Suva 67095', 'Un palonnier (traverse) optimise la capacité et limite l''angle d''inclinaison dangereux', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000444', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000439', 'Vérifier d''où le monteur accroche les sangles en haut.', 'Risque hauteur', 'Suva 67095', 'Il doit utiliser une nacelle/plateforme élévatrice pour le travail au faîte du camion', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000445', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000440', 'Vérifier le bas de l''élément de bois sur table.', 'Atelier', 'Suva 67095', 'Une poutre butoir empêche le panneau de glisser lors du levage depuis la table', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000446', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000441', 'Vérifier comment les grands panneaux sont stockés.', 'Stockage vertical', 'Suva 67095', 'Stocker dans des structures (racks) empêchant de façon fiable le renversement', true, false);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, objet, base_legale, explications, actif, is_custom) VALUES ('cc000000-0000-4000-a000-000000000447', '00000000-0000-0000-0000-000000000001', 'aa000000-0000-4000-a000-000000000026', 'bb000000-0000-4000-a000-000000000442', 'Contrôler le stockage temporaire et l''élingage des éléments.', 'Fiche 67095', 'Suva 67095', 'Chaque élément doit être étayé individuellement (sangles, chaînes ; pas de serre-joints) pour empêcher le basculement [42]. Il faut tenir compte du centre de gravité lors du levage.', true, false);
